1	<!DOCTYPE html>
2	<html lang="en">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width, initial-scale=1.0">
6	<title>Stockio Dashboard</title>
7	<script src="https://cdn.jsdelivr.net/npm/chart.js@4"></script>
8	<style>
9	  :root {
10	    --bg: #0f0f23;
11	    --card: #1a1a3e;
12	    --card-border: #2a2a5e;
13	    --text: #e0e0e0;
14	    --text-dim: #8888aa;
15	    --accent: #4fc3f7;
16	    --green: #4caf50;
17	    --red: #ef5350;
18	    --hold: #9e9e9e;
19	    --font: system-ui, -apple-system, sans-serif;
20	    --mono: 'JetBrains Mono', 'Fira Code', monospace;
21	  }
22	  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
23	  body { background: var(--bg); color: var(--text); font-family: var(--font); line-height: 1.5; padding: 0; }
24	  a { color: var(--accent); text-decoration: none; }
25	
26	  /* Header */
27	  .header {
28	    display: flex; align-items: center; gap: 16px; padding: 12px 24px;
29	    background: #12122a; border-bottom: 1px solid var(--card-border); flex-wrap: wrap;
30	  }
31	  .header-title { font-size: 1.4rem; font-weight: 700; color: #fff; }
32	  .version-badge {
33	    font-size: 0.7rem; background: var(--accent); color: #000; padding: 2px 8px;
34	    border-radius: 10px; font-weight: 600; vertical-align: middle;
35	  }
36	  .header-spacer { flex: 1; }
37	  .instance-toggle { display: flex; gap: 0; }
38	  .instance-btn {
39	    padding: 6px 18px; border: 1px solid var(--card-border); background: var(--card);
40	    color: var(--text-dim); cursor: pointer; font-size: 0.85rem; font-family: var(--font);
41	    transition: all 0.15s;
42	  }
43	  .instance-btn:first-child { border-radius: 6px 0 0 6px; }
44	  .instance-btn:last-child { border-radius: 0 6px 6px 0; }
45	  .instance-btn.active { background: var(--accent); color: #000; font-weight: 600; border-color: var(--accent); }
46	  .ctrl-btn {
47	    padding: 6px 16px; border: 1px solid var(--card-border); border-radius: 6px;
48	    background: var(--card); color: var(--text); cursor: pointer; font-size: 0.85rem;
49	    font-family: var(--font); transition: all 0.15s;
50	  }
51	  .ctrl-btn:hover { border-color: var(--accent); }
52	  .ctrl-btn.running { border-color: var(--red); color: var(--red); }
53	  .ctrl-btn.stopped { border-color: var(--green); color: var(--green); }
54	  .status-dot {
55	    width: 10px; height: 10px; border-radius: 50%; display: inline-block;
56	  }
57	  .status-dot.running { background: var(--green); box-shadow: 0 0 6px var(--green); }
58	  .status-dot.stopped { background: var(--red); }
59	  .status-dot.halted { background: #ff9800; box-shadow: 0 0 6px #ff9800; }
60	  .status-label { font-size: 0.85rem; color: var(--text-dim); margin-left: 4px; }
61	  .gear-btn {
62	    background: none; border: none; color: var(--text-dim); cursor: pointer;
63	    font-size: 1.3rem; padding: 4px 8px; transition: color 0.15s;
64	  }
65	  .gear-btn:hover { color: var(--accent); }
66	
67	  /* Main layout */
68	  .main { max-width: 1400px; margin: 0 auto; padding: 20px 24px; }
69	
70	  /* Cards row */
71	  .cards { display: grid; grid-template-columns: repeat(4, 1fr); gap: 16px; margin-bottom: 20px; }
72	  .card {
73	    background: var(--card); border: 1px solid var(--card-border); border-radius: 10px;
74	    padding: 18px 20px;
75	  }
76	  .card-label { font-size: 0.78rem; color: var(--text-dim); text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 4px; }
77	  .card-value { font-size: 1.6rem; font-weight: 700; font-family: var(--mono); }
78	  .card-value.positive { color: var(--green); }
79	  .card-value.negative { color: var(--red); }
80	
81	  /* Panels */
82	  .panel {
83	    background: var(--card); border: 1px solid var(--card-border); border-radius: 10px;
84	    padding: 18px 20px; margin-bottom: 20px;
85	  }
86	  .panel-title { font-size: 1rem; font-weight: 600; margin-bottom: 12px; color: #fff; }
87	
88	  /* Tables */
89	  .table-wrap { overflow-x: auto; }
90	  table { width: 100%; border-collapse: collapse; font-size: 0.82rem; }
91	  th { text-align: left; color: var(--text-dim); font-weight: 500; padding: 8px 10px;
92	       border-bottom: 1px solid var(--card-border); white-space: nowrap; font-size: 0.75rem;
93	       text-transform: uppercase; letter-spacing: 0.5px; }
94	  td { padding: 7px 10px; border-bottom: 1px solid #1e1e40; white-space: nowrap; font-family: var(--mono); font-size: 0.8rem; }
95	  tr:hover td { background: rgba(79, 195, 247, 0.04); }
96	  .dir-buy { color: var(--green); font-weight: 600; }
97	  .dir-sell { color: var(--red); font-weight: 600; }
98	  .dir-hold { color: var(--hold); }
99	  .scrollable-table { max-height: 340px; overflow-y: auto; }
100	
101	  /* Chart */
102	  .chart-container { position: relative; height: 280px; }
103	
104	  /* Bot log */
105	  .log-entry {
106	    border: 1px solid var(--card-border); border-radius: 8px; margin-bottom: 8px;
107	    overflow: hidden;
108	  }
109	  .log-header {
110	    display: flex; justify-content: space-between; align-items: center;
111	    padding: 10px 14px; cursor: pointer; background: rgba(255,255,255,0.02);
112	    transition: background 0.15s;
113	  }
114	  .log-header:hover { background: rgba(79, 195, 247, 0.05); }
115	  .log-cycle { font-weight: 600; font-family: var(--mono); font-size: 0.85rem; }
116	  .log-time { font-size: 0.75rem; color: var(--text-dim); }
117	  .log-arrow { color: var(--text-dim); transition: transform 0.2s; font-size: 0.8rem; }
118	  .log-arrow.open { transform: rotate(90deg); }
119	  .log-body { padding: 0 14px 12px; display: none; font-size: 0.82rem; }
120	  .log-body.open { display: block; }
121	  .log-stat { display: inline-block; margin-right: 18px; margin-top: 4px; }
122	  .log-stat-label { color: var(--text-dim); font-size: 0.75rem; }
123	  .log-stat-value { font-family: var(--mono); font-weight: 600; }
124	
125	  /* Engine footer */
126	  .engine-footer {
127	    display: flex; flex-wrap: wrap; gap: 24px; align-items: center;
128	    padding: 14px 20px; background: var(--card); border: 1px solid var(--card-border);
129	    border-radius: 10px; margin-bottom: 20px; font-size: 0.82rem;
130	  }
131	  .engine-stat-label { color: var(--text-dim); font-size: 0.72rem; text-transform: uppercase; }
132	  .engine-stat-value { font-family: var(--mono); font-weight: 600; }
133	  .halted-warning { color: #ff9800; font-weight: 600; }
134	
135	  /* Settings modal */
136	  .modal-overlay {
137	    display: none; position: fixed; inset: 0; background: rgba(0,0,0,0.7);
138	    z-index: 1000; justify-content: center; align-items: center;
139	  }
140	  .modal-overlay.open { display: flex; }
141	  .modal {
142	    background: var(--card); border: 1px solid var(--card-border); border-radius: 12px;
143	    padding: 24px 28px; width: 460px; max-width: 95vw; max-height: 90vh; overflow-y: auto;
144	  }
145	  .modal-title { font-size: 1.1rem; font-weight: 700; color: #fff; margin-bottom: 18px; }
146	  .form-group { margin-bottom: 14px; }
147	  .form-label { display: block; font-size: 0.78rem; color: var(--text-dim); margin-bottom: 4px; text-transform: uppercase; letter-spacing: 0.3px; }
148	  .form-input {
149	    width: 100%; padding: 8px 12px; background: var(--bg); border: 1px solid var(--card-border);
150	    border-radius: 6px; color: var(--text); font-family: var(--mono); font-size: 0.85rem;
151	  }
152	  .form-input:focus { outline: none; border-color: var(--accent); }
153	  .modal-actions { display: flex; justify-content: flex-end; gap: 10px; margin-top: 20px; }
154	  .btn-save {
155	    padding: 8px 20px; background: var(--accent); color: #000; border: none;
156	    border-radius: 6px; cursor: pointer; font-weight: 600; font-family: var(--font); font-size: 0.85rem;
157	  }
158	  .btn-cancel {
159	    padding: 8px 20px; background: transparent; color: var(--text-dim); border: 1px solid var(--card-border);
160	    border-radius: 6px; cursor: pointer; font-family: var(--font); font-size: 0.85rem;
161	  }
162	  .btn-save:hover { filter: brightness(1.1); }
163	  .btn-cancel:hover { border-color: var(--text-dim); }
164	
165	  .no-data { color: var(--text-dim); font-style: italic; padding: 16px 0; font-size: 0.85rem; }
166	
167	  /* Responsive */
168	  @media (max-width: 900px) {
169	    .cards { grid-template-columns: repeat(2, 1fr); }
170	  }
171	  @media (max-width: 500px) {
172	    .cards { grid-template-columns: 1fr; }
173	    .header { padding: 10px 14px; gap: 10px; }
174	    .main { padding: 14px; }
175	  }
176	
177	  /* Scrollbar */
178	  ::-webkit-scrollbar { width: 6px; height: 6px; }
179	  ::-webkit-scrollbar-track { background: var(--bg); }
180	  ::-webkit-scrollbar-thumb { background: var(--card-border); border-radius: 3px; }
181	</style>
182	</head>
183	<body>
184	
185	<!-- Header -->
186	<div class="header">
187	  <span class="header-title">Stockio <span class="version-badge">{{ version|default('v0.1') }}</span></span>
188	  <div class="header-spacer"></div>
189	  <div class="instance-toggle">
190	    <button class="instance-btn active" data-instance="paper" onclick="switchInstance('paper')">Paper</button>
191	    <button class="instance-btn" data-instance="live" onclick="switchInstance('live')">Live</button>
192	  </div>
193	  <button id="startStopBtn" class="ctrl-btn stopped" onclick="toggleInstance()">Start</button>
194	  <span id="statusDot" class="status-dot stopped"></span>
195	  <span id="statusLabel" class="status-label">Stopped</span>
196	  <button class="gear-btn" onclick="openSettings()" title="Settings">&#9881;</button>
197	</div>
198	
199	<!-- Main -->
200	<div class="main">
201	
202	  <!-- Portfolio Cards -->
203	  <div class="cards">
204	    <div class="card">
205	      <div class="card-label">Balance</div>
206	      <div class="card-value" id="cardBalance">--</div>
207	    </div>
208	    <div class="card">
209	      <div class="card-label">Equity</div>
210	      <div class="card-value" id="cardEquity">--</div>
211	    </div>
212	    <div class="card">
213	      <div class="card-label">Unrealized P&amp;L</div>
214	      <div class="card-value" id="cardPnl">--</div>
215	    </div>
216	    <div class="card">
217	      <div class="card-label">Open Positions</div>
218	      <div class="card-value" id="cardPositions">--</div>
219	    </div>
220	  </div>
221	
222	  <!-- P&L Chart -->
223	  <div class="panel">
224	    <div class="panel-title">Equity Over Time</div>
225	    <div class="chart-container">
226	      <canvas id="equityChart"></canvas>
227	    </div>
228	  </div>
229	
230	  <!-- Signals -->
231	  <div class="panel">
232	    <div class="panel-title">Signals</div>
233	    <div class="table-wrap" id="signalsWrap">
234	      <p class="no-data">Loading...</p>
235	    </div>
236	  </div>
237	
238	  <!-- Trade History -->
239	  <div class="panel">
240	    <div class="panel-title">Trade History</div>
241	    <div class="scrollable-table">
242	      <div class="table-wrap" id="tradesWrap">
243	        <p class="no-data">Loading...</p>
244	      </div>
245	    </div>
246	  </div>
247	
248	  <!-- Bot Thinking Log -->
249	  <div class="panel">
250	    <div class="panel-title">Bot Thinking Log</div>
251	    <div id="botLogWrap">
252	      <p class="no-data">Loading...</p>
253	    </div>
254	  </div>
255	
256	  <!-- Engine Status Footer -->
257	  <div class="engine-footer" id="engineFooter">
258	    <div><div class="engine-stat-label">Cycles</div><div class="engine-stat-value" id="engCycles">--</div></div>
259	    <div><div class="engine-stat-label">Model Accuracy</div><div class="engine-stat-value" id="engAccuracy">--</div></div>
260	    <div><div class="engine-stat-label">Training Samples</div><div class="engine-stat-value" id="engSamples">--</div></div>
261	    <div><div class="engine-stat-label">Pending Outcomes</div><div class="engine-stat-value" id="engPending">--</div></div>
262	    <div><div class="engine-stat-label">Instruments</div><div class="engine-stat-value" id="engInstruments">--</div></div>
263	    <div id="engHaltWrap" style="display:none;"><div class="engine-stat-label">Circuit Breaker</div><div class="halted-warning" id="engHalt">HALTED</div></div>
264	  </div>
265	
266	</div><!-- /main -->
267	
268	<!-- Settings Modal -->
269	<div class="modal-overlay" id="settingsModal">
270	  <div class="modal">
271	    <div class="modal-title">Settings</div>
272	    <div class="form-group"><label class="form-label">Min Confidence</label><input class="form-input" id="set_min_confidence" type="number" step="0.01"></div>
273	    <div class="form-group"><label class="form-label">Risk Per Trade</label><input class="form-input" id="set_risk_per_trade" type="number" step="0.001"></div>
274	    <div class="form-group"><label class="form-label">Stop Loss ATR Mult</label><input class="form-input" id="set_stop_loss_atr_mult" type="number" step="0.1"></div>
275	    <div class="form-group"><label class="form-label">Take Profit ATR Mult</label><input class="form-input" id="set_take_profit_atr_mult" type="number" step="0.1"></div>
276	    <div class="form-group"><label class="form-label">Max Positions</label><input class="form-input" id="set_max_positions" type="number" step="1"></div>
277	    <div class="form-group"><label class="form-label">Daily Loss Limit</label><input class="form-input" id="set_daily_loss_limit" type="number" step="0.01"></div>
278	    <div class="form-group"><label class="form-label">Max Drawdown</label><input class="form-input" id="set_max_drawdown" type="number" step="0.01"></div>
279	    <div class="form-group"><label class="form-label">Cycle Seconds</label><input class="form-input" id="set_cycle_seconds" type="number" step="1" min="60" placeholder="300 = 5min"></div>
280	    <div class="form-group"><label class="form-label">Sentiment Refresh (sec)</label><input class="form-input" id="set_sentiment_refresh_seconds" type="number" step="1" min="300" placeholder="3600 = 1hr"></div>
281	    <div class="modal-actions">
282	      <button class="btn-cancel" onclick="closeSettings()">Cancel</button>
283	      <button class="btn-save" onclick="saveSettings()">Save</button>
284	    </div>
285	  </div>
286	</div>
287	
288	<script>
289	/* ── State ── */
290	let activeInstance = 'paper';
291	let equityChart = null;
292	let refreshTimer = null;
293	
294	/* ── Helpers ── */
295	function api(path) {
296	  const sep = path.includes('?') ? '&' : '?';
297	  return path + sep + 'instance=' + activeInstance;
298	}
299	
300	async function fetchJSON(path) {
301	  try {
302	    const r = await fetch(api(path));
303	    if (!r.ok) throw new Error(r.status);
304	    return await r.json();
305	  } catch (e) {
306	    console.warn('Fetch failed:', path, e);
307	    return null;
308	  }
309	}
310	
311	function fmt(n, decimals) {
312	  if (n == null || isNaN(n)) return '--';
313	  decimals = decimals != null ? decimals : 2;
314	  return Number(n).toLocaleString(undefined, { minimumFractionDigits: decimals, maximumFractionDigits: decimals });
315	}
316	
317	function pnlClass(v) {
318	  if (v > 0) return 'positive';
319	  if (v < 0) return 'negative';
320	  return '';
321	}
322	
323	function dirClass(d) {
324	  if (!d) return '';
325	  const u = d.toUpperCase();
326	  if (u === 'BUY' || u === 'LONG') return 'dir-buy';
327	  if (u === 'SELL' || u === 'SHORT') return 'dir-sell';
328	  return 'dir-hold';
329	}
330	
331	function escHtml(s) {
332	  if (s == null) return '';
333	  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
334	}
335	
336	function shortTime(ts) {
337	  if (!ts) return '--';
338	  try {
339	    const d = new Date(ts);
340	    return d.toLocaleString(undefined, { month:'short', day:'numeric', hour:'2-digit', minute:'2-digit', second:'2-digit' });
341	  } catch { return ts; }
342	}
343	
344	/* ── Instance toggle ── */
345	function switchInstance(name) {
346	  activeInstance = name;
347	  document.querySelectorAll('.instance-btn').forEach(b => {
348	    b.classList.toggle('active', b.dataset.instance === name);
349	  });
350	  refreshAll();
351	}
352	
353	/* ── Start / Stop ── */
354	async function toggleInstance() {
355	  const btn = document.getElementById('startStopBtn');
356	  const isRunning = btn.classList.contains('running');
357	  const action = isRunning ? 'stop' : 'start';
358	  try {
359	    const r = await fetch('/api/instances/' + activeInstance + '/' + action, { method: 'POST' });
360	    if (!r.ok) throw new Error(r.status);
361	  } catch (e) {
362	    console.warn('Toggle failed:', e);
363	  }
364	  setTimeout(refreshInstances, 500);
365	}
366	
367	/* ── Refresh functions ── */
368	async function refreshStatus() {
369	  const d = await fetchJSON('/api/status');
370	  if (!d) return;
371	  const cur = d.currency || '';
372	  document.getElementById('cardBalance').textContent = fmt(d.balance) + ' ' + cur;
373	  document.getElementById('cardEquity').textContent = fmt(d.equity) + ' ' + cur;
374	  const pnlEl = document.getElementById('cardPnl');
375	  pnlEl.textContent = (d.unrealized_pnl >= 0 ? '+' : '') + fmt(d.unrealized_pnl) + ' ' + cur;
376	  pnlEl.className = 'card-value ' + pnlClass(d.unrealized_pnl);
377	  document.getElementById('cardPositions').textContent = d.open_positions != null ? d.open_positions : '--';
378	}
379	
380	async function refreshInstances() {
381	  const d = await fetchJSON('/api/instances');
382	  if (!d) return;
383	  const inst = d[activeInstance];
384	  if (!inst) return;
385	  const btn = document.getElementById('startStopBtn');
386	  const dot = document.getElementById('statusDot');
387	  const lbl = document.getElementById('statusLabel');
388	  const running = inst.running;
389	  const hasError = inst.last_error;
390	
391	  btn.textContent = running ? 'Stop' : 'Start';
392	  btn.className = 'ctrl-btn ' + (running ? 'running' : 'stopped');
393	  dot.className = 'status-dot ' + (running ? 'running' : 'stopped');
394	  lbl.textContent = running ? 'Running' : 'Stopped';
395	
396	  // Override with halt status from engine
397	  const eng = await fetchJSON('/api/engine-status');
398	  if (eng && eng.halted) {
399	    dot.className = 'status-dot halted';
400	    lbl.textContent = 'Halted';
401	  }
402	}
403	
404	async function refreshChart() {
405	  const data = await fetchJSON('/api/snapshots');
406	  if (!data || !data.length) return;
407	  const labels = data.map(s => {
408	    try {
409	      const d = new Date(s.timestamp);
410	      return d.toLocaleTimeString(undefined, { hour:'2-digit', minute:'2-digit' });
411	    } catch { return ''; }
412	  });
413	  const values = data.map(s => s.equity);
414	
415	  if (!equityChart) {
416	    const ctx = document.getElementById('equityChart').getContext('2d');
417	    equityChart = new Chart(ctx, {
418	      type: 'line',
419	      data: {
420	        labels: labels,
421	        datasets: [{
422	          label: 'Equity',
423	          data: values,
424	          borderColor: '#4fc3f7',
425	          backgroundColor: 'rgba(79, 195, 247, 0.08)',
426	          fill: true,
427	          tension: 0.3,
428	          pointRadius: 0,
429	          borderWidth: 2,
430	        }]
431	      },
432	      options: {
433	        responsive: true,
434	        maintainAspectRatio: false,
435	        plugins: { legend: { display: false } },
436	        scales: {
437	          x: {
438	            ticks: { color: '#8888aa', font: { size: 10 }, maxTicksLimit: 12 },
439	            grid: { color: 'rgba(255,255,255,0.04)' },
440	          },
441	          y: {
442	            ticks: { color: '#8888aa', font: { family: "'JetBrains Mono', monospace", size: 11 } },
443	            grid: { color: 'rgba(255,255,255,0.04)' },
444	          }
445	        },
446	        interaction: { intersect: false, mode: 'index' },
447	      }
448	    });
449	  } else {
450	    equityChart.data.labels = labels;
451	    equityChart.data.datasets[0].data = values;
452	    equityChart.update('none');
453	  }
454	}
455	
456	async function refreshSignals() {
457	  const wrap = document.getElementById('signalsWrap');
458	  const [signals, sentiment] = await Promise.all([
459	    fetchJSON('/api/signals'),
460	    fetchJSON('/api/sentiment'),
461	  ]);
462	  if (!signals || !signals.length) {
463	    wrap.innerHTML = '<p class="no-data">No signals available</p>';
464	    return;
465	  }
466	  const sentMap = (sentiment && sentiment.combined) ? sentiment.combined : (sentiment || {});
467	  let html = '<table><thead><tr><th>Instrument</th><th>Direction</th><th>Confidence</th><th>Sentiment</th><th>RSI 14</th><th>MACD</th><th>ADX</th></tr></thead><tbody>';
468	  signals.forEach(s => {
469	    const sent = sentMap[s.instrument] != null ? sentMap[s.instrument] : s.sentiment;
470	    const sentColor = sent > 0 ? 'color:var(--green)' : (sent < 0 ? 'color:var(--red)' : '');
471	    html += '<tr>'
472	      + '<td>' + escHtml(s.instrument) + '</td>'
473	      + '<td class="' + dirClass(s.direction) + '">' + escHtml(s.direction) + '</td>'
