/* ── Sentiment Breakdown ── */
let sentimentChart = null;
async function refreshSentiment() {
  const data = await fetchJSON('/api/sentiment/breakdown');
  if (!data) return;
  const instruments = Object.keys(data);
  if (!instruments.length) return;
  const newsScores = instruments.map(k => data[k].news_score || 0);
  const trumpScores = instruments.map(k => data[k].trump_score || 0);
  if (!sentimentChart) {
    const ctx = document.getElementById('sentimentChart').getContext('2d');
    sentimentChart = new Chart(ctx, {
      type: 'bar',
      data: {
        labels: instruments,
        datasets: [
          { label: 'News', data: newsScores, backgroundColor: '#4fc3f7' },
          { label: 'Trump', data: trumpScores, backgroundColor: '#ff9800' },
        ]
      },
      options: {
        indexAxis: 'y', responsive: true, maintainAspectRatio: false,
        scales: {
          x: { min: -1, max: 1, ticks: { color: '#8888aa', font: { size: 10 } }, grid: { color: 'rgba(255,255,255,0.04)' } },
          y: { ticks: { color: '#e0e0e0', font: { size: 11 } }, grid: { display: false } }
        },
        plugins: { legend: { labels: { color: '#8888aa', font: { size: 11 } } } }
      }
    });
  } else {
    sentimentChart.data.labels = instruments;
    sentimentChart.data.datasets[0].data = newsScores;
    sentimentChart.data.datasets[1].data = trumpScores;
    sentimentChart.update('none');
  }
  let scoresHtml = '';
  instruments.forEach(k => {
    const c = data[k].combined;
    const color = c > 0 ? 'var(--green)' : c < 0 ? 'var(--red)' : 'var(--text-dim)';
    scoresHtml += '<span class="sentiment-chip" style="border-color:' + color + '">' + escHtml(k) + ': <span style="color:' + color + '">' + (c != null ? Number(c).toFixed(3) : '--') + '</span></span>';
  });
  document.getElementById('sentimentScores').innerHTML = scoresHtml;
}

