/* ── Technical Indicators ── */
async function refreshIndicators() {
  const data = await fetchJSON('/api/indicators');
  const wrap = document.getElementById('indicatorGrid');
  if (!data || !Object.keys(data).length) { wrap.innerHTML = '<p class="no-data">No indicator data</p>'; return; }

  function bar(val, min, max, color) {
    const pct = Math.max(0, Math.min(100, ((val - min) / (max - min)) * 100));
    return '<div class="gauge-bar"><div class="gauge-fill" style="width:' + pct.toFixed(1) + '%;background:' + color + '"></div></div>';
  }
  function bipolar(val, absMax, posColor, negColor) {
    const clamped = Math.max(-absMax, Math.min(absMax, val));
    const pct = Math.abs(clamped) / absMax * 50;
    const left = clamped >= 0 ? 50 : 50 - pct;
    const color = clamped >= 0 ? posColor : negColor;
    return '<div class="gauge-bar-bipolar"><div class="gauge-center"></div><div class="gauge-fill-bi" style="left:' + left.toFixed(1) + '%;width:' + pct.toFixed(1) + '%;background:' + color + '"></div></div>';
  }

  let html = '';
  Object.keys(data).forEach(inst => {
    const d = data[inst];
    const rsi = d.rsi_14;
    const rsiColor = rsi != null ? (rsi < 30 ? 'var(--green)' : rsi > 70 ? 'var(--red)' : 'var(--text-dim)') : 'var(--text-dim)';
    const bbColor = d.bb_percent_b != null ? (d.bb_percent_b < 0.2 ? 'var(--green)' : d.bb_percent_b > 0.8 ? 'var(--red)' : 'var(--accent)') : 'var(--text-dim)';
    const adxColor = d.adx != null && d.adx > 25 ? 'var(--green)' : 'var(--text-dim)';

    html += '<div class="indicator-row">'
      + '<span class="indicator-row-label">' + escHtml(inst) + '</span>'
      + '<div class="gauge-group">'
      + '<div class="mini-gauge"><span class="mini-gauge-label">RSI 14</span>' + bar(rsi || 50, 0, 100, rsiColor) + '<span class="gauge-value" style="color:' + rsiColor + '">' + (rsi != null ? rsi.toFixed(1) : '--') + '</span></div>'
      + '<div class="mini-gauge"><span class="mini-gauge-label">BB %B</span>' + bar((d.bb_percent_b || 0.5) * 100, 0, 100, bbColor) + '<span class="gauge-value">' + (d.bb_percent_b != null ? d.bb_percent_b.toFixed(2) : '--') + '</span></div>'
      + '<div class="mini-gauge"><span class="mini-gauge-label">ADX</span>' + bar(d.adx || 0, 0, 60, adxColor) + '<span class="gauge-value" style="color:' + adxColor + '">' + (d.adx != null ? d.adx.toFixed(1) : '--') + '</span></div>'
      + '<div class="mini-gauge"><span class="mini-gauge-label">MACD</span>' + bipolar(d.macd_histogram || 0, 0.005, 'var(--green)', 'var(--red)') + '<span class="gauge-value">' + (d.macd_histogram != null ? d.macd_histogram.toFixed(5) : '--') + '</span></div>'
      + '</div></div>';
  });
  wrap.innerHTML = html;
}

/* ── Decision Waterfall ── */
async function refreshWaterfall() {
  const data = await fetchJSON('/api/scoring-breakdown');
  const wrap = document.getElementById('waterfallList');
  if (!data || !Object.keys(data).length) { wrap.innerHTML = '<p class="no-data">No scoring data</p>'; return; }

  let html = '';
  Object.keys(data).forEach(inst => {
    const d = data[inst];
    const comps = d.components || [];
    const nonMult = comps.filter(c => !c.is_multiplier);
    const totalAbs = nonMult.reduce((s, c) => s + Math.abs(c.score || 0), 0) || 1;
    const dirCls = dirClass(d.direction);
    const confPct = d.confidence != null ? (d.confidence * 100).toFixed(1) + '%' : '--';

    let barHtml = '';
    let detailHtml = '';
    nonMult.forEach(c => {
      const w = (Math.abs(c.score || 0) / totalAbs * 100);
      const color = (c.score || 0) >= 0 ? 'var(--green)' : 'var(--red)';
      barHtml += '<div class="waterfall-seg" style="width:' + w.toFixed(1) + '%;background:' + color + '" title="' + escHtml(c.name) + ': ' + (c.score != null ? c.score.toFixed(3) : '') + '">' + (w > 8 ? escHtml(c.name) : '') + '</div>';
      detailHtml += '<div class="waterfall-detail-row"><span>' + escHtml(c.name) + (c.is_multiplier ? ' (mult)' : '') + '</span><span style="font-family:var(--mono)">val: ' + (c.value != null ? Number(c.value).toFixed(4) : '--') + ' &rarr; score: <span style="color:' + color + '">' + (c.score != null ? c.score.toFixed(3) : '--') + '</span></span></div>';
    });
    comps.filter(c => c.is_multiplier).forEach(c => {
      detailHtml += '<div class="waterfall-detail-row"><span>' + escHtml(c.name) + ' <span style="color:var(--accent)">(multiplier)</span></span><span style="font-family:var(--mono)">val: ' + (c.value != null ? Number(c.value).toFixed(4) : '--') + ' &rarr; &times;' + (c.score != null ? c.score.toFixed(3) : '--') + '</span></div>';
    });

    html += '<div class="waterfall-item">'
      + '<div class="waterfall-header" onclick="toggleWaterfall(this)">'
      + '<span class="waterfall-label">' + escHtml(inst) + '</span>'
      + '<div class="waterfall-summary"><span class="' + dirCls + '">' + escHtml(d.direction || 'HOLD') + '</span><span style="font-family:var(--mono)">' + confPct + '</span><span class="waterfall-arrow">&#9654;</span></div>'
      + '</div>'
      + '<div class="waterfall-body">'
      + '<div class="waterfall-bar-track">' + barHtml + '</div>'
      + detailHtml
      + '</div></div>';
  });
  wrap.innerHTML = html;
}
function toggleWaterfall(header) {
  const body = header.nextElementSibling;
  const arrow = header.querySelector('.waterfall-arrow');
  body.classList.toggle('open');
  arrow.classList.toggle('open');
