  const data = await fetchJSON('/api/model-learning');
  const wrap = document.getElementById('modelLearning');
  if (!data) { wrap.innerHTML = '<p class="no-data">No model data</p>'; return; }

  const accPct = data.rolling_accuracy != null ? (data.rolling_accuracy * 100).toFixed(1) + '%' : '--';
  const degradedHtml = data.is_degraded ? ' <span class="degraded-badge">DEGRADED</span>' : '';
  const retrain = data.last_retrain ? shortTime(data.last_retrain) : '--';

  let leftHtml = '<div class="model-stats">'
    + '<div class="model-stat-card"><div class="card-label">Rolling Accuracy</div><div class="card-value">' + accPct + degradedHtml + '</div></div>'
    + '<div class="model-stat-card"><div class="card-label">Training Samples</div><div class="card-value">' + (data.training_samples != null ? data.training_samples : '--') + '</div></div>'
    + '<div class="model-stat-card"><div class="card-label">Pending Outcomes</div><div class="card-value">' + (data.pending_outcomes != null ? data.pending_outcomes : '--') + '</div></div>'
    + '<div class="model-stat-card"><div class="card-label">Last Retrain</div><div class="card-value" style="font-size:0.8rem">' + retrain + '</div></div>'
    + '</div>';

  let rightHtml = '';
  if (data.recent_outcomes && data.recent_outcomes.length) {
    rightHtml += '<div><span style="font-size:0.78rem;color:var(--text-dim)">RECENT PREDICTIONS</span><div class="streak-grid">';
    data.recent_outcomes.forEach(o => {
      rightHtml += '<div class="streak-dot ' + (o === 1 ? 'win' : 'loss') + '" title="' + (o === 1 ? 'Correct' : 'Wrong') + '"></div>';
    });
    rightHtml += '</div></div>';
  }
  if (data.cv_accuracies && data.cv_accuracies.length) {
    rightHtml += '<div class="cv-chart-container"><canvas id="cvChart"></canvas></div>';
  }

  wrap.innerHTML = '<div>' + leftHtml + '</div><div>' + rightHtml + '</div>';

  if (data.cv_accuracies && data.cv_accuracies.length) {
    const cvCtx = document.getElementById('cvChart');
    if (cvCtx) {
      if (cvChart) cvChart.destroy();
      cvChart = new Chart(cvCtx.getContext('2d'), {
        type: 'bar',
        data: {
          labels: data.cv_accuracies.map((_, i) => 'F' + (i + 1)),
          datasets: [{ data: data.cv_accuracies.map(v => (v * 100)), backgroundColor: 'var(--accent)', borderRadius: 3 }]
        },
        options: {
          responsive: true, maintainAspectRatio: false,
          plugins: { legend: { display: false }, tooltip: { callbacks: { label: ctx => ctx.parsed.y.toFixed(1) + '%' } } },
          scales: {
            x: { ticks: { color: '#8888aa', font: { size: 9 } }, grid: { display: false } },
            y: { min: 0, max: 100, ticks: { color: '#8888aa', font: { size: 9 }, callback: v => v + '%' }, grid: { color: 'rgba(255,255,255,0.04)' } }
          }
        }
      });
    }
  }
}

/* ── Trade Outcomes ── */
let donutChart = null;
async function refreshTradeOutcomes() {
  const data = await fetchJSON('/api/trade-outcomes');
  const wrap = document.getElementById('tradeOutcomes');
  if (!data) { wrap.innerHTML = '<p class="no-data">No outcome data</p>'; return; }

  const winPct = data.win_ratio != null ? (data.win_ratio * 100).toFixed(1) + '%' : '--';
  const winColor = data.win_ratio != null && data.win_ratio >= 0.5 ? 'var(--green)' : 'var(--red)';

  let html = '<div class="outcomes-top">'
    + '<div class="outcomes-big-stats">'
    + '<div class="big-stat"><div class="big-stat-value">' + (data.total != null ? data.total : '--') + '</div><div class="big-stat-label">Total</div></div>'
    + '<div class="big-stat"><div class="big-stat-value" style="color:var(--green)">' + (data.wins != null ? data.wins : '--') + '</div><div class="big-stat-label">Wins</div></div>'
    + '<div class="big-stat"><div class="big-stat-value" style="color:var(--red)">' + (data.losses != null ? data.losses : '--') + '</div><div class="big-stat-label">Losses</div></div>'
    + '<div class="big-stat"><div class="big-stat-value" style="color:' + winColor + '">' + winPct + '</div><div class="big-stat-label">Win Rate</div></div>'
    + '</div>'
    + '<div class="donut-container"><canvas id="donutChart"></canvas></div>'
    + '</div>';

  // Direction breakdown
  if (data.by_direction) {
    const buyWin = data.by_direction.BUY ? (data.by_direction.BUY.win_ratio * 100) : 0;
    const sellWin = data.by_direction.SELL ? (data.by_direction.SELL.win_ratio * 100) : 0;
    html += '<div class="direction-bars">'
      + '<div class="dir-bar-group"><div class="dir-bar-label">BUY Win Rate: <span style="font-family:var(--mono);color:var(--green)">' + buyWin.toFixed(1) + '%</span></div><div class="dir-bar-track"><div class="dir-bar-fill" style="width:' + buyWin.toFixed(1) + '%;background:var(--green)"></div></div></div>'
      + '<div class="dir-bar-group"><div class="dir-bar-label">SELL Win Rate: <span style="font-family:var(--mono);color:var(--red)">' + sellWin.toFixed(1) + '%</span></div><div class="dir-bar-track"><div class="dir-bar-fill" style="width:' + sellWin.toFixed(1) + '%;background:var(--red)"></div></div></div>'
      + '</div>';
  }

  // Per-instrument table
  if (data.by_instrument && Object.keys(data.by_instrument).length) {
    html += '<div class="table-wrap" style="margin-top:12px"><table><thead><tr><th>Instrument</th><th>Trades</th><th>Wins</th><th>Losses</th><th>Win %</th></tr></thead><tbody>';
    Object.entries(data.by_instrument).forEach(([name, d]) => {
      const wr = d.win_ratio != null ? (d.win_ratio * 100).toFixed(1) + '%' : '--';
      const wrColor = d.win_ratio != null && d.win_ratio >= 0.5 ? 'color:var(--green)' : 'color:var(--red)';
      html += '<tr><td>' + escHtml(name) + '</td><td>' + (d.total || 0) + '</td><td style="color:var(--green)">' + (d.wins || 0) + '</td><td style="color:var(--red)">' + (d.losses || 0) + '</td><td style="' + wrColor + '">' + wr + '</td></tr>';
    });
    html += '</tbody></table></div>';
  }

  // Recent outcomes
  if (data.recent && data.recent.length) {
    html += '<div style="margin-top:14px"><span style="font-size:0.78rem;color:var(--text-dim);text-transform:uppercase">Recent Outcomes</span><div class="recent-outcomes">';
    data.recent.slice(0, 10).forEach(r => {
      const isWin = r.label === 1 || r.label === 'win';
      const icon = isWin ? '&#10003;' : '&#10007;';
      const cls = isWin ? 'win' : 'loss';
      html += '<div class="outcome-item"><span class="outcome-icon ' + cls + '">' + icon + '</span>' + escHtml(r.instrument) + ' ' + escHtml(r.direction) + '</div>';
    });
    html += '</div></div>';
  }

  wrap.innerHTML = html;

  // Donut chart
  const donutEl = document.getElementById('donutChart');
  if (donutEl && data.wins != null && data.losses != null) {
    if (donutChart) donutChart.destroy();
    donutChart = new Chart(donutEl.getContext('2d'), {
      type: 'doughnut',
      data: {
        labels: ['Wins', 'Losses'],
        datasets: [{ data: [data.wins || 0, data.losses || 0], backgroundColor: ['#4caf50', '#ef5350'], borderWidth: 0 }]
      },
      options: {
        responsive: true, maintainAspectRatio: false, cutout: '65%',
        plugins: { legend: { display: false } }
      }
    });
  }
}

